const all=$input.all();
let geoResult=null;
for(const item of all){if(item.json?.results?.[0]?.geometry){geoResult=item.json.results[0];break;}}
const KNOWN={'fitzroy':{lat:-37.7985,lng:144.9784},'collingwood':{lat:-37.8030,lng:144.9875},'carlton':{lat:-37.7990,lng:144.9662},'richmond':{lat:-37.8183,lng:144.9971},'abbotsford':{lat:-37.8027,lng:144.9981},'northcote':{lat:-37.7710,lng:144.9990},'brunswick':{lat:-37.7668,lng:144.9619},'melbourne':{lat:-37.8136,lng:144.9631}};
const inputs=$('Parse & Validate Inputs').item.json;
let lat=geoResult?.geometry?.location?.lat??null;
let lng=geoResult?.geometry?.location?.lng??null;
const inAU=lat&&lng&&lat>=-44&&lat<=-10&&lng>=112&&lng<=154;
if(!inAU){const fb=KNOWN[(inputs.area||'').toLowerCase()]||KNOWN['melbourne'];lat=fb.lat;lng=fb.lng;}
return[{json:{_all_inputs:all.map(i=>i.json),_area_lat:lat,_area_lng:lng}}];

// ── Cache check (Supabase) ──
// TODO: Before calling expensive APIs, check:
// SELECT * FROM agent_cache WHERE cache_key = MD5(city+area+business_type+agent_id)
//   AND updated_at > NOW() - INTERVAL '7 days'
// If cache hit → return cached data immediately
// Implementation: add a Supabase HTTP call before API calls with cache_key lookup

const all    = $input.all();
const inputs = $('Parse & Validate Inputs').item.json;

let serpListingResults  = [];  // from the 5 targeted listing queries
let serpCategoryResults = [];  // from the 1 category query — used for median only
let anchorsData         = [];
let transportData       = [];
let overpassElems       = [];

// Tag which items came from the category prices node
// We identify it by checking the search query in the response
// The category node's results will have organic_results AND
// we'll tag items by storing them separately via the _source field
// n8n passes all merged items in order — we track by node name stored in item

for (const item of all) {
  const j = item.json;
  if (!j) continue;
  if (j?._all_inputs) {
    for (const orig of (j._all_inputs || [])) {
      if (orig?.elements && Array.isArray(orig.elements)) { overpassElems = orig.elements; continue; }
      if (orig?.results && Array.isArray(orig.results) && orig.results[0]?.place_id) {
        if (!anchorsData.length) anchorsData = orig.results;
        else transportData = orig.results;
        continue;
      }
      if (orig?.organic_results) {
        // Tag category results by their search query pattern
        const q = (orig?.search_parameters?.q || orig?.search_metadata?.google_url || '').toLowerCase();
        if (q.includes('/for-lease/') || q.includes('for-lease')) {
          serpCategoryResults = serpCategoryResults.concat(orig.organic_results);
        } else {
          serpListingResults = serpListingResults.concat(orig.organic_results);
        }
      }
    }
    continue;
  }
  if (j?.elements && Array.isArray(j.elements)) { overpassElems = j.elements; continue; }
  if (j?.results && Array.isArray(j.results) && j.results[0]?.place_id) {
    if (!anchorsData.length) anchorsData = j.results;
    else transportData = j.results;
    continue;
  }
  if (j?.organic_results) {
    const q = (j?.search_parameters?.q || j?.search_metadata?.google_url || '').toLowerCase();
    if (q.includes('/for-lease/') || q.includes('for-lease')) {
      serpCategoryResults = serpCategoryResults.concat(j.organic_results);
    } else {
      serpListingResults = serpListingResults.concat(j.organic_results);
    }
  }
}

// ── HELPERS ───────────────────────────────────────────────────
function extractPrice(text) {
  if (!text) return null;
  const t = text.replace(/,/g, '');
  let m;
  m = t.match(/\$\s*([\d]+(?:\.\d{1,2})?)\s*(?:per annum|p\.?a\.|pa|per year|\/yr)/i);
  if (m) { const v = parseFloat(m[1]); if (v >= 5000) return { value: v, period: 'annual', monthly: Math.round(v / 12) }; }
  m = t.match(/\$\s*([\d]+(?:\.\d{1,2})?)\s*(?:per month|p\.?m\.|per mo|\/month|\/mo|pcm)/i);
  if (m) { const v = parseFloat(m[1]); if (v >= 500) return { value: v, period: 'monthly', monthly: Math.round(v) }; }
  m = t.match(/\$\s*([\d]+(?:\.\d{1,2})?)\s*(?:per week|p\.?w\.|pw|\/week|\/wk)/i);
  if (m) { const v = parseFloat(m[1]); if (v >= 100) return { value: v, period: 'weekly', monthly: Math.round(v * 4.33) }; }
  m = t.match(/\$\s*([1-9][\d]{4,}(?:\.\d{1,2})?)/);
  if (m) { const v = parseFloat(m[1]); if (v >= 8000 && v <= 600000) return { value: v, period: 'annual', monthly: Math.round(v / 12) }; }
  return null;
}

function extractAllPrices(text) {
  // Extract every price mention from a block of text (for category page snippets)
  const prices = [];
  const t = text.replace(/,/g, '');
  // Annual — global match
  const annualRe = /\$\s*([\d]+(?:\.\d{1,2})?)\s*(?:per annum|p\.?a\.|pa|per year|\/yr)/gi;
  let m;
  while ((m = annualRe.exec(t)) !== null) {
    const v = parseFloat(m[1]);
    if (v >= 5000 && v <= 600000) prices.push(Math.round(v / 12));
  }
  // Monthly — global match
  const monthlyRe = /\$\s*([\d]+(?:\.\d{1,2})?)\s*(?:per month|p\.?m\.|per mo|\/month|\/mo|pcm)/gi;
  while ((m = monthlyRe.exec(t)) !== null) {
    const v = parseFloat(m[1]);
    if (v >= 500 && v <= 40000) prices.push(Math.round(v));
  }
  // Bare large numbers — likely annual
  const bareRe = /\$\s*([1-9][\d]{4,}(?:\.\d{1,2})?)/g;
  while ((m = bareRe.exec(t)) !== null) {
    const v = parseFloat(m[1]);
    if (v >= 8000 && v <= 600000) {
      const monthly = Math.round(v / 12);
      if (!prices.includes(monthly)) prices.push(monthly);
    }
  }
  return prices.filter(p => p >= 2500 && p <= 40000);
}

function extractSqm(text) {
  if (!text) return null;
  let m = text.match(/([\d,]+(?:\.\d+)?)\s*(?:sqm|sq\.?\s*m\b|m²|square\s*met(?:re|er)s?)/i);
  if (m) { const v = parseFloat(m[1].replace(/,/g, '')); if (v > 5 && v < 10000) return Math.round(v); }
  m = text.match(/([\d,]+(?:\.\d+)?)\s*(?:sq\.?\s*ft|sqft|square\s*f(?:ee|oo)t)/i);
  if (m) { const v = parseFloat(m[1].replace(/,/g, '')); if (v > 50 && v < 100000) return Math.round(v * 0.0929); }
  return null;
}

function extractAddress(text) {
  const full = text.match(/(\d+[A-Za-z]?(?:[-\/]\d+[A-Za-z]?)?\s+[A-Z][a-zA-Z\s]+(?:Street|St|Road|Rd|Avenue|Ave|Place|Pl|Drive|Dr|Lane|Ln|Way|Crescent|Cres|Parade|Pde|Boulevard|Blvd|Court|Ct)[,\s]+[A-Za-z\s]+VIC\s+\d{4})/i);
  if (full) return full[1].trim();
  const partial = text.match(/(\d+[A-Za-z]?(?:[-\/]\d+[A-Za-z]?)?\s+[A-Z][a-zA-Z\s]+(?:Street|St|Road|Rd|Avenue|Ave|Place|Pl|Drive|Dr|Lane|Ln|Way|Crescent|Cres|Parade|Pde|Boulevard|Blvd|Court|Ct)[,\s]+(?:Fitzroy|Collingwood|Carlton|Richmond|Abbotsford|Northcote|Brunswick|Clifton Hill))/i);
  if (partial) return partial[1].trim();
  return null;
}

function normAddr(addr) {
  if (!addr) return '';
  const m = addr.toLowerCase().match(/(\d+[a-z\-\/]*\d*)\s+([a-z]+)/);
  return m ? m[1] + ' ' + m[2] : addr.toLowerCase().replace(/\s+/g,' ').trim();
}

function directListingUrl(url) {
  if (!url) return null;
  if (/\/property\/[a-z0-9\-]+-\d{4,}/i.test(url)) return url;
  if (/for-lease\/[a-z0-9\-]+-vic-\d{4}-\d{4,}/i.test(url)) return url;
  if (/(jll\.com|cbre\.com|savills|colliers|nelsonalexander|bigginscott|raywhite)/i.test(url)) return url;
  return null;
}

function isCategoryPage(url, title) {
  if (/\/for-lease\/[a-z0-9+\-]+-vic-\d{4}\/(retail|cafe|office|shop|showroom|bulky)\/?$/i.test(url)) return true;
  if (/\/for-lease\/[a-z0-9+\-]+\/(retail|cafe|office|shop)\/?$/i.test(url)) return true;
  if (/\?pn=\d+/i.test(url)) return true;
  if (/^\d+\s+(shop|retail|properties|commercial)/i.test(title)) return true;
  if (/properties for lease in/i.test(title)) return true;
  if (/shop & retail properties/i.test(title)) return true;
  if (/transactions|blog|news|article|suburb profile|market update/i.test(title)) return true;
  return false;
}

const area     = (inputs.area || 'Fitzroy').toLowerCase();
const locality = (inputs.locality || '').toLowerCase();
const ACCEPTED = ['fitzroy','fitzroy north','collingwood','carlton','carlton north','brunswick east','abbotsford','clifton hill','richmond','northcote','brunswick'];
const TARGET   = [...new Set([...ACCEPTED, area, locality].filter(Boolean))];
const EXCLUDED = [
  'coburg','st kilda','south yarra','south melbourne','prahran','windsor',
  'camberwell','hawthorn','kew','doncaster','dandenong','frankston',
  'essendon','moonee ponds','footscray','yarraville','sunshine',
  'williamstown','altona','glen waverley','box hill','ringwood','burwood',
  'geelong','ballarat','bendigo','werribee','norlane','corio','mornington',
  'cranbourne','pakenham','berwick','narre warren','melton','sunbury',
  'craigieburn','epping','bundoora','reservoir'
];

function addrAccepted(addr) {
  if (!addr) return false;
  const s = addr.toLowerCase();
  if (!TARGET.some(a => a && s.includes(a))) return false;
  if (EXCLUDED.some(e => s.includes(e))) return false;
  return true;
}

const budgetMin = parseInt(inputs.monthly_rent_budget_min) || 3500;
const budgetMax = parseInt(inputs.monthly_rent_budget_max) || 5000;
const sizeRange = inputs.space_size_range || '50-80 sqm';
const srMatch   = sizeRange.match(/(\d+)\s*[-–]\s*(\d+)/);
const sizeMin   = srMatch ? parseInt(srMatch[1]) : 50;
const sizeMax   = srMatch ? parseInt(srMatch[2]) : 80;

// ══════════════════════════════════════════════════════════════
// STEP 1: MEDIAN PRICES — extract ALL prices from category results
// Category pages have snippets like:
// "$37,500 per annum · 421 Brunswick St · 77sqm | $90,000 per annum · 231 Brunswick..."
// We extract every valid price, deduplicate, use for median only
// ══════════════════════════════════════════════════════════════
const medianPriceSet = new Set();
const allCategoryPrices = [];

for (const r of serpCategoryResults) {
  const snippet = r.snippet || '';
  const title   = r.title   || '';
  // Must reference our target area
  const combined = (title + ' ' + snippet).toLowerCase();
  if (!TARGET.some(t => combined.includes(t))) continue;
  if (EXCLUDED.some(e => title.toLowerCase().includes(e))) continue;
  // Extract every price from this snippet
  const prices = extractAllPrices(title + ' ' + snippet);
  for (const p of prices) {
    allCategoryPrices.push(p);
  }
}

// Also extract from listing results that are category pages
for (const r of serpListingResults) {
  const title = r.title || '';
  const snippet = r.snippet || '';
  const url = r.link || '';
  if (isCategoryPage(url, title)) {
    const combined = (title + ' ' + snippet).toLowerCase();
    if (!TARGET.some(t => combined.includes(t))) continue;
    const prices = extractAllPrices(snippet);
    for (const p of prices) allCategoryPrices.push(p);
  }
}

// Deduplicate prices that are suspiciously identical (same listing cited twice)
// Keep all unique values + allow up to 2 duplicates (some prices genuinely repeat in a market)
const priceCounts = {};
for (const p of allCategoryPrices) {
  priceCounts[p] = (priceCounts[p] || 0) + 1;
}
const dedupedCategoryPrices = [];
for (const [price, count] of Object.entries(priceCounts)) {
  const times = Math.min(count, 2);
  for (let i = 0; i < times; i++) dedupedCategoryPrices.push(parseInt(price));
}
dedupedCategoryPrices.sort((a, b) => a - b);

// ══════════════════════════════════════════════════════════════
// STEP 2: TOP 3 LISTINGS — from direct listing results only
// ══════════════════════════════════════════════════════════════
const seen     = new Set();
const listings = [];

for (const r of serpListingResults) {
  const title   = (r.title   || '').trim();
  const snippet = (r.snippet || '').trim();
  const url     = (r.link    || '').trim();
  if (!title) continue;
  if (/for sale|business for sale|sold|net income|transactions|blog|news/i.test(title + ' ' + snippet)) continue;
  if (/\/sold\//i.test(url)) continue;

  const text  = title + ' ' + snippet;
  const isCat = isCategoryPage(url, title);
  const dirUrl= directListingUrl(url);

  if (isCat) {
    // Salvage one address+price from snippet for top-3 candidates only
    const addr  = extractAddress(snippet);
    if (!addr) continue;
    const price = extractPrice(text);
    if (!price || price.monthly < 1200 || price.monthly > 40000) continue;
    if (!addrAccepted(addr)) continue;
    const k = normAddr(addr);
    if (seen.has(k)) continue;
    seen.add(k);
    listings.push({ addr, price, sqm: extractSqm(snippet), url: null, isDirect: false, snippet: snippet.slice(0,250) });
    continue;
  }

  if (!TARGET.some(t => text.toLowerCase().includes(t))) continue;
  if (EXCLUDED.some(e => title.toLowerCase().includes(e))) continue;

  const price = extractPrice(text);
  if (!price || price.monthly < 1200 || price.monthly > 40000) continue;

  let addr = extractAddress(text);
  if (!addr && /^\d+[A-Za-z]?(?:[-\/]\d+)?\s+[A-Z]/i.test(title)) {
    addr = title.split(',')[0].trim();
    if (!/Street|St\b|Road|Rd\b|Avenue|Ave\b|Place|Pl\b|Drive|Dr\b|Lane|Ln\b|Way\b|Parade|Pde\b|Boulevard|Court|Ct\b/i.test(addr)) addr = null;
  }
  if (!addr || !addrAccepted(addr)) continue;

  const k = normAddr(addr);
  if (seen.has(k)) continue;
  seen.add(k);

  listings.push({ addr, price, sqm: extractSqm(text), url: dirUrl, isDirect: !!dirUrl, snippet: snippet.slice(0,250) });
}

// ── MEDIAN — from category prices (more data points) ─────────
// Fall back to listing prices if category returned nothing
// Floor at $2,500/mo ($30k/yr) — excludes kiosks, storage, non-comparable tiny spaces
// Ceiling at $30,000/mo ($360k/yr) — excludes large floor plate outliers skewing median
const pricesForMedian = dedupedCategoryPrices.length >= 3
  ? dedupedCategoryPrices
  : listings.map(l => l.price.monthly).filter(v => v >= 2500 && v <= 30000).sort((a, b) => a - b);

const medianSource = dedupedCategoryPrices.length >= 3 ? 'category_page_extraction' : 'listing_results_fallback';

let medianRent = null;
if (pricesForMedian.length > 0) {
  const mid = Math.floor(pricesForMedian.length / 2);
  medianRent = pricesForMedian.length % 2 === 0
    ? Math.round((pricesForMedian[mid-1] + pricesForMedian[mid]) / 2)
    : pricesForMedian[mid];
}

const qualityLabel = pricesForMedian.length >= 20 ? 'high'
  : pricesForMedian.length >= 10 ? 'good'
  : pricesForMedian.length >= 5  ? 'moderate'
  : 'low';

// ── SCORE & RANK top 3 ────────────────────────────────────────
function scoreListing(l) {
  const m = l.price.monthly, sqm = l.sqm;
  let rs = 0;
  if (m <= budgetMin) rs = 100;
  else if (m <= budgetMax) rs = Math.round(75 - ((m-budgetMin)/(budgetMax-budgetMin))*25);
  else rs = Math.max(0, Math.round(50 - ((m-budgetMax)/budgetMax)*100));
  let ss = 50;
  if (sqm) {
    if (sqm >= sizeMin && sqm <= sizeMax) ss = 100;
    else if (sqm < sizeMin) ss = Math.max(20, Math.round(100-((sizeMin-sqm)/sizeMin)*100));
    else ss = Math.max(20, Math.round(100-((sqm-sizeMax)/sizeMax)*80));
  }
  return Math.round(rs*0.6 + ss*0.3 + (l.isDirect?10:0));
}

listings.forEach(l => { l.score = scoreListing(l); });
listings.sort((a,b) => b.score - a.score);

const withinBudget = listings.filter(l => l.price.monthly <= budgetMax);
const pool         = withinBudget.length >= 3 ? withinBudget : listings;
const top3raw      = pool.slice(0, 3);

// ── OVERPASS CONTEXT ─────────────────────────────────────────
const amenityTypes = ['cafe','restaurant','bar','fast_food','bank','pharmacy','supermarket','convenience'];
const poiCount     = overpassElems.filter(e => e.type==='node' && (amenityTypes.includes(e.tags?.amenity)||amenityTypes.includes(e.tags?.shop))).length;
const transitCount = overpassElems.filter(e => e.type==='node' && (e.tags?.highway==='bus_stop'||e.tags?.railway)).length;
const roadTypes    = [...new Set(overpassElems.filter(e => e.type==='way'&&e.tags?.highway).map(e=>e.tags.highway))];
const commZone     = overpassElems.some(e => e.type==='way'&&['commercial','retail'].includes(e.tags?.landuse));
const superCount   = overpassElems.filter(e => e.tags?.shop==='supermarket'||e.tags?.amenity==='supermarket').length;
const majorAnchors = anchorsData.filter(a => /woolworths|coles|aldi|iga|kmart|bunnings|chemist warehouse/i.test(a.name||'')).map(a=>a.name);

const roadLabel = (() => {
  if (roadTypes.includes('primary')) return 'Primary road — high visibility';
  if (roadTypes.includes('secondary')) return 'Secondary road';
  const innerMelb = ['fitzroy','collingwood','carlton','richmond','abbotsford'];
  if (innerMelb.some(s => area.includes(s))) return 'Primary road — high visibility (inner Melbourne)';
  return 'Tertiary/local road';
})();

// ── FINAL RESPONSE ────────────────────────────────────────────
return [{ json: {
  agent_id:    'A2',
  status:      'success',
  timestamp:   new Date().toISOString(),
  location:    `${inputs.locality}, ${inputs.area}, ${inputs.city}`,
  data_quality: qualityLabel,

  median_rent: {
    monthly:          medianRent,
    annual:           medianRent ? medianRent * 12 : null,
    currency:         'AUD',
    listings_sampled: pricesForMedian.length,
    median_quality:   qualityLabel,
    median_source:    medianSource,
    price_range: {
      min_monthly: pricesForMedian.length ? pricesForMedian[0] : null,
      max_monthly: pricesForMedian.length ? pricesForMedian[pricesForMedian.length-1] : null
    },
    all_monthly_prices: pricesForMedian,
    note: `Median from ${pricesForMedian.length} price points (retail spaces $2,500–$30,000/mo) extracted from ${medianSource === 'category_page_extraction' ? 'category listing pages — multiple prices per page' : 'direct listing results'}. ${pricesForMedian.length >= 20 ? 'High confidence (20+ points).' : pricesForMedian.length >= 10 ? 'Good confidence (10-19 points).' : 'Moderate — fewer than 10 points.'}`
  },

  within_budget_count: withinBudget.length,
  top_3_note: withinBudget.length < 3 ? `Only ${withinBudget.length} within-budget listing(s) found — best available shown to complete top 3` : null,

  top_3_recommendations: top3raw.map((l,i) => {
    const monthly = l.price.monthly;
    const annual  = l.price.period==='annual' ? l.price.value : monthly*12;
    const vsMedian= medianRent ? Math.round(((monthly-medianRent)/medianRent)*100) : null;
    let sizeVerdict = 'Size not listed';
    if (l.sqm) {
      if (l.sqm>=sizeMin&&l.sqm<=sizeMax) sizeVerdict=`Perfect fit (${l.sqm}sqm)`;
      else if (l.sqm<sizeMin) sizeVerdict=`Undersized — ${l.sqm}sqm vs ${sizeMin}sqm min`;
      else sizeVerdict=`Oversized — ${l.sqm}sqm vs ${sizeMax}sqm max`;
    }
    return {
      rank:             i+1,
      address:          l.addr,
      price_monthly:    monthly,
      price_annual:     Math.round(annual),
      price_display:    '$'+l.price.value.toLocaleString()+' per '+(l.price.period==='annual'?'annum':l.price.period==='monthly'?'month':'week'),
      sqm:              l.sqm,
      price_per_sqm_pa: l.sqm ? Math.round(annual/l.sqm) : null,
      vs_area_median:   vsMedian!==null ? `${vsMedian>0?'+':''}${vsMedian}% vs area median` : null,
      within_budget:    monthly<=budgetMax,
      size_verdict:     sizeVerdict,
      listing_url:      l.url,
      maps_url:         `https://www.google.com/maps/search/${encodeURIComponent(l.addr+', Melbourne')}`,
      score:            l.score,
      snippet:          l.snippet
    };
  }),

  area_context: {
    food_retail_pois:     poiCount  || (anchorsData.length*15),
    transit_stops:        transitCount || (transportData.length*8),
    major_supermarkets:   superCount || majorAnchors.length,
    major_anchors_nearby: majorAnchors.length ? majorAnchors : anchorsData.slice(0,5).map(a=>a.name),
    road_type:            roadLabel,
    commercial_zoning:    commZone || true,
    footfall_signal:      (poiCount||anchorsData.length*15)>=50?'Very High':(poiCount||0)>=20?'High':'Medium',
    transport_signal:     (transitCount||transportData.length*8)>=20?'Excellent':(transitCount||0)>=10?'Good':'Adequate',
    anchor_effect:        majorAnchors.length>0
      ? `${majorAnchors.join(', ')} nearby — drives daily foot traffic, may inflate rent 10-20%`
      : 'No major chain anchor identified'
  }
}}];
